document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll("[data-contao-circles]").forEach(function(wrapper){var area=wrapper.querySelector("[data-circle-stage]")||wrapper.querySelector(".circle-area"),circles=Array.prototype.slice.call(area.querySelectorAll(".circle")),textArea=wrapper.querySelector(".text-area"),source=wrapper.querySelector(".content-source");if(!area||!circles.length||!textArea||!source)return;var activeIndex=Math.max(0,circles.findIndex(function(circle){return circle.classList.contains("active")})),distanceRatio=.7,triangleHeightRatio=distanceRatio*Math.sqrt(3)/2;function getLayout(count,width,height,padding){var size=Math.max(0,Math.floor(Math.min((width-padding*2)/(1+distanceRatio),(height-padding*2)/(1+triangleHeightRatio),Math.min(width,height)*.55))),slots=[],centerX=width/2,centerY=height*.465,distance=size*distanceRatio,triangleHeight=size*triangleHeightRatio;if(count===3)return{size:size,slots:[{x:centerX,y:centerY-triangleHeight/2,className:"pos-top"},{x:centerX+distance/2,y:centerY+triangleHeight/2,className:"pos-right"},{x:centerX-distance/2,y:centerY+triangleHeight/2,className:"pos-left"}]};for(var i=0;i<count;i++){var angle=-Math.PI/2+i*2*Math.PI/count,radius=size*distanceRatio/2;slots.push({x:centerX+Math.cos(angle)*radius,y:centerY+Math.sin(angle)*radius,className:"pos-top"})}return{size:size,slots:slots}}function render(){var rect=area.getBoundingClientRect(),width=rect.width,height=rect.height;if(width<=0||height<=0)return;var padding=Math.max(6,Math.min(width,height)*.025),layout=getLayout(circles.length,width,height,padding),size=layout.size,fontSize=Math.max(14,Math.min(26,Math.round(size*.095)));circles.forEach(function(circle,index){var slotIndex=(index-activeIndex+circles.length)%circles.length,slot=layout.slots[slotIndex]||layout.slots[0];circle.style.setProperty("--circle-size",size+"px");circle.style.setProperty("--circle-font-size",fontSize+"px");circle.style.setProperty("--circle-left",Math.round(slot.x)+"px");circle.style.setProperty("--circle-top",Math.round(slot.y)+"px");circle.classList.toggle("active",index===activeIndex);circle.classList.remove("pos-top","pos-left","pos-right");circle.classList.add(slot.className)})}function updateText(index){var key=circles[index].getAttribute("data-key"),content=source.querySelector('[data-content="'+key+'"]');textArea.innerHTML=content?content.innerHTML:""}circles.forEach(function(circle,targetIndex){circle.addEventListener("click",function(){if(targetIndex===activeIndex)return;for(;activeIndex!==targetIndex;)activeIndex=(activeIndex+1)%circles.length;render();updateText(activeIndex)})});render();updateText(activeIndex);if("ResizeObserver"in window)new ResizeObserver(render).observe(area);else window.addEventListener("resize",render)})});
